#!/bin/bash
# v2 video pass: Chapter I rebuild + connective shots for II-IV, 480p std, maximalist prompts.
cd /Users/dawndrain/Code/videogen/long_game
mkdir -p outputs/video2
V=outputs/video2; F=frames; F2=frames2; A=anchors

W="Wardrobe and character lock: Cass is 17, white, lean, pale, short dark tousled hair, watchful grey eyes, wearing a plain heather-grey t-shirt, dark slim jeans, white sneakers. Deshawn is 17, Black, very tall and long-limbed, expressive mobile face, buzzed hair, wearing an iridescent blue-and-orange patterned track jacket over a black tee, black joggers, chunky white high-tops. Milo is 17, white, compact, curly brown hair, thin wire-frame glasses, wearing an olive-green hoodie and blue jeans. The arcade is spotless and gleaming, polished near-black floor with clean neon reflections, magenta and cyan light, every cabinet in perfect repair; it is never dirty or grimy."
N="Photorealistic, natural human motion and facial performance, correct anatomy and proportions. No slow motion unless stated. No text, captions, subtitles, dates or logos appearing anywhere. Characters keep exactly the same faces and clothes as in the reference images for the entire clip."
GESTURE="the water-greeting gesture: right hand held flat, palm down, fingers together, moving in a slow clockwise circle three times, about a hand's width above the water"

gen() {
  local name="$1" dur="$2"; shift 2
  local out
  out=$(./gen.py video "$@" --resolution 480p --std --duration "$dur" 2>/dev/null | tail -1)
  if [ -f "$out" ]; then cp "$out" "$V/$name.mp4"; echo "OK $name"; else echo "FAIL $name"; fi
}

# --- Chapter I rebuild ---
gen 1_1_arcade_wide 10 "Wide shot inside the spotless futuristic retro arcade at night. Deshawn dances on the DDR machine's light-up pad at one-third speed with deliberate theatrical grace: a lazy spin, an exaggerated slow lunge onto one arrow panel, arms flowing, head tipped back laughing, fully human weight and balance in every step, his feet always landing on the pad. Milo stands just off the pad filming him on a phone, grinning, shifting to keep him in frame. In the far background Cass stays where he is, reading the placard, not watching. Camera: slow lateral dolly right at eye level. Audio: pumping chiptune dance track from the cabinet, arcade ambience, Milo laughing, and Deshawn calling out happily 'Bro reads the safety warnings on the skee-ball!'. $W $N" --start-image $F2/1_1_arcade_wide.png --image $A/deshawn.png --image $A/milo.png &
gen 1_2_placard 8 "Medium shot. Cass stands very still in the neon-lit aisle reading a small yellow maintenance placard taped to a machine, eyes moving down the text, face quiet and intent. Halfway through the shot Milo leans into frame over his shoulder from behind, pushes his glasses up with one finger, reads the placard, and his face lights up with delighted mischief; he announces, like a ring announcer introducing a boxer: 'The Deep End. They put the Deep End back.' Cass does not look at him. Camera: slow push-in from a three-quarter angle. Audio: muffled arcade noise, a distant dance track, Milo's line clear and close. $W $N" --start-image $F/1_2_placard.png --image $A/cass_17.png --image $A/milo.png &
gen 1_3_approach 8 "The camera pulls back smoothly ahead of the three boys as they walk fast down the arcade aisle toward the lens at normal speed, jostling: Deshawn shoves Cass's shoulder, Cass shoves back without smiling, Milo skips a step to keep up, Deshawn and Milo grinning, Cass half-grinning despite himself. Dialogue as they walk - Cass, flat: 'It's off. It says it's off.' Deshawn, delighted, drawing the word out: 'It says temporarily.' Audio: their footsteps and voices close, arcade noise receding behind them, a low ominous electronic hum slowly rising underneath. $W $N" --start-image $F2/1_3_approach.png --image $A/cass_17.png --image $A/deshawn.png --image $A/milo.png &
gen 1_4_screen_cu 6 "Slow steady camera push-in on the small glowing screen and the yellow out-of-service tape below it. The screen text stays perfectly legible and completely unchanged for the whole shot, exactly as in the start image. In the final second the screen flickers once, slightly. Audio: the arcade noise fades to near silence, leaving one low electronic hum and a single soft click. Photorealistic; the existing screen text and tape remain exactly as they are; no new text appears." --start-image $F/1_4_screen_cu.png &
gen 1_5_deshawn_run 12 "Deshawn lies reclined in the tooth-white pod chair with the headset over his eyes. Performance in strict order: for the first three seconds his hands twitch minutely on the armrests and his mouth moves silently; then he laughs out loud once at something no one else can see; then he tears the headset off, gulping air, eyes wet and wide and delighted, sitting up all at once in one natural motion; for the rest of the shot he grabs Cass's forearm and babbles breathlessly, joyful: 'Sochi. Two golds. There was a woman - there was a whole -' while looking at his own hands like they belong to a stranger who led an interesting life. Cass and Milo lean in on either side of the chair, Milo filming on his phone, Cass wary. Camera: locked medium shot with a slight slow push. Audio: chair servos, his gasp, the dialogue clear and close, arcade ambience low. $W $N" --start-image $F/1_5_deshawn_chair.png --image $A/deshawn.png --image $A/cass_17.png --image $A/milo.png &
gen 1_6_goading 8 "Beside the tooth-white pod chair: Deshawn points both index fingers at Cass with a huge delighted grin and says 'Cass has to.' Milo, deadpan, arms crossed, says 'He has to.' A beat. Cass looks at the chair, looks at his friends, and sits down into the chair in one decisive motion, pulling the headset down over his eyes, saying as he does: 'Harder than his. I'm not doing biathlon.' Milo, already turning to the maintenance panel, grinning: 'Way harder.' Camera: medium two-shot that rotates slowly to follow Cass into the chair. Audio: the dialogue close and natural, arcade ambience low, a faint hum underneath. $W $N" --start-image $F2/1_6_goading.png --image $A/cass_17.png --image $A/deshawn.png --image $A/milo.png &
gen 1_7_toggle 8 "Extreme close-up on the open maintenance panel of the white machine: Milo's finger slides a small metal toggle switch from the up position to the down position with a hard click. The camera tilts up to Milo's face lit green by the panel light, grinning the specific grin of a boy doing something hilarious and terrible. Off-screen, Deshawn's voice, warm and cheerful: 'Have a good life.' Then the machine's screen light blooms and floods the entire frame to pure white over the final two seconds. Audio: the click, the line, then a single rising clean electronic tone that cuts to silence exactly as the frame reaches white. $W $N" --start-image $F/1_6_toggle.png --image $A/milo.png --image $A/deshawn.png &

# --- Chapter II additions ---
gen 2_2_water_carry 8 "The gaunt boy trudges through the deep mud carrying the wooden yoke with a heavy clay water pot swinging at each end, slipping once and recovering, breath visible in the cold air, wind flattening the wet grass. As he passes, in the background by a doorway, the old woman in rags goes on talking softly to the empty air, gesturing gently to nobody; the boy walks past without a glance and no villager looks at her either. Handheld camera tracks alongside him at shoulder height, documentary feel. Audio: cold wind, creaking wood, sloshing water, morning birds, and under it the faint continuous murmur of the old woman. $N" --start-image $F2/2_2_water_carry.png --image $A/cass_17.png --image $A/touched_woman.png &
gen 2_4_remembering 12 "Dark hut interior at dawn. The gaunt boy lies on the packed earth floor exactly as he wakes every time; his eye snaps open; two full seconds of total stillness. Then his whole body convulses upright in one terrified motion and he claws at his own face and temples with both hands, searching for a headset that is not there, fingers dragging down his cheeks, hyperventilating. He screams, raw, voice breaking: 'Milo! Turn it off! Turn it OFF! I want OUT!' A woman rushes in from the doorway, drops to her knees, and wraps him against her chest exactly the way a mother holds a fevered child, one hand smoothing his hair; he fights her for one second and then collapses into her, sobbing, fists clenched in her dress. Camera: handheld, close, urgent. Audio: his ragged breathing and scream, her low soothing murmur in a strange language, wind under the door. Photorealistic, natural motion, correct anatomy; no text anywhere." --start-image $F/2_1_eye_open.png --image $A/cass_17.png &
gen 3_1_salt_water 8 "The teenage boy carefully spoons water into the sick child's mouth; the child swallows weakly, then again more strongly. As he works he murmurs, half to the watching mother and half to himself, slowly, like teaching: 'Salt. Honey. Clean water. Keep giving it - however fast it runs through her.' The mother watches his mouth as if the words are a spell, then presses her hands to her own mouth as the child swallows again. Villagers murmur at the doorway. Firelight flickers over everything. Audio: the fire crackling, his quiet steady words, a soft ripple of awe from the doorway. $N" --start-image $F/3_1_salt_water.png --image $A/cass_17.png &
gen 3_3_good_years 12 "The young bearded king is having the time of several lives. Performance beats in order: he throws his head back and roars with genuine laughter at the feast; he slaps the shoulder of the chieftain beside him mid-joke; he leans over the wooden game board of holes and pebbles and makes one quick move that makes the two warriors groan and shove each other; his young queen leans in and whispers something in his ear and he laughs even harder, wiping one eye with the back of his wine hand; he tosses a scrap of meat to a dog who catches it. Everything about him is loose, golden, wildly alive. Camera: slow warm float through the torchlit feast toward him. Audio: drums and pipes, roaring hall laughter, pebbles clacking on the wood board, and his big open laugh riding above it all. $N" --start-image $F2/3_3_good_years.png --image $A/cass_28.png &
wait

# --- Chapter IV additions ---
gen 4_2_fountain_gesture 10 "The kneeling woman at the marble fountain performs ${GESTURE} over the mouth of her clay jar, murmuring to the water, exactly the same slow ceremonial hand movement shown in the reference video; then she dips the jar and fills it, stands, and walks away as if nothing happened. Behind her, the walking man stops dead in the middle of the street the instant he sees her hand move, and does not move again for the rest of the shot, staring, his face going from confusion to recognition to quiet devastation. The street sounds fall away gradually until only the running fountain remains. Audio: street murmur fading out, the fountain running clear and alone. $N" --start-image $F/4_2_fountain_gesture.png --image $A/cass_45.png --video outputs/video/3_3_water_greeting.mp4 &
gen 4_7_icecream_bench 10 "The sweating man works the row of snow-packed clay jars with total experimental focus, at normal speed: he pours one measured bronze scoop of grey salt into a jar and stirs the slush; frost blooms brighter on the jar's outside; he lifts the small thimble cup out of one jar and tips it - still liquid cream, he scowls; he lifts the thimble from the next jar and turns it fully upside down - the cream holds solid - and his face breaks into slow astonished triumph; he laughs once, alone, the short laugh of a man who has just beaten the universe at cards, and reaches for the larger bronze pot of cream. Camera: start close on the frosting jar, pull back to a medium shot as he works. Audio: the scrape of the bronze scoop, the crunch of salted snow, cicadas outside the window, and his single delighted laugh. $N" --start-image $F2/4_7_icecream_bench.png --image $A/cass_45.png &
wait
echo ALLDONE
